-- Migracion: desglosa 'Importados' en sus rubros reales
-- (Peluqueria y Barberia, Estetica, Decoracion, Almacenamiento, Oficina, Herramientas)
-- y reubica los que en realidad eran Carniceria/Panaderia/Frio/Hogar mal clasificados.
-- Correr una sola vez en el SQL Editor de Supabase.

-- 1) Nuevas categorias
insert into categories (name, slug, sort_order) values
  ('Peluquería y Barbería', 'peluqueria-barberia', 8),
  ('Estética', 'estetica', 9),
  ('Decoración', 'decoracion', 10),
  ('Almacenamiento', 'almacenamiento', 11),
  ('Oficina', 'oficina', 12),
  ('Herramientas', 'herramientas', 13)
on conflict (slug) do update set name = excluded.name, sort_order = excluded.sort_order;

-- 2) Marca Kemei (antes se guardaba como 'Behmont' por error)
insert into brands (name, sort_order) values ('Kemei', 201)
on conflict (name) do nothing;

